HostWebServiceJaspiERP.Call(&EmpCod, &EmpWebHost, &EmpWebBaseUrl, &EmpWebPor)

&HttpClient.Host = &EmpWebHost //servidor  sistema.efrete.com
&HttpClient.Port = &EmpWebPor
&HttpClient.BaseUrl = &EmpWebBaseUrl //diretório virtual do serviço 
&HttpClient.Secure = 0 //false

&LongVarchar  =  '<soapenv:Envelope xmlns:soapenv="http://schemas.xmlsoap.org/soap/envelope/" xmlns:erp="ERP">'
&LongVarchar +=  '   <soapenv:Header/>'
&LongVarchar +=  '   <soapenv:Body>'
&LongVarchar +=  '      <erp:ppWbsDadosClientes.Execute>'
&LongVarchar +=  '      	<erp:Sdtsyncall>'

For Each Order EmpCod
	Where EmpCod = &EmpCod

	&LongVarchar +=  '          	<erp:SyncOque>GRAVARINF_CLIENTE</erp:SyncOque>'
	&LongVarchar +=  '          	<erp:SyncKey>'+EmpCodSec.Trim()+'</erp:SyncKey>'

	&LongVarchar +=  '          	<erp:Sync>'

	For Each Order EmpCod, FilVctCer
		Where FilAmbEms = TAmb.Producao or FilAmbEmsMdfe = TAmb.Producao
		Where not FilVctCer.IsEmpty() and not FilVctCer.IsNull()		

           &LongVarchar +=  '          	<erp:SyncItem>'
           &LongVarchar +=  '          		<erp:SyncCod>CliVctCer</erp:SyncCod>'
           &LongVarchar +=  '          		<erp:SyncValue>'+FilVctCer.ToFormattedString()+'</erp:SyncValue>'
           &LongVarchar +=  '          	</erp:SyncItem>'		   
	  Exit
	EndFor

	&LongVarchar +=  '          	</erp:Sync>'

	&LongVarchar +=  '          </erp:Sdtsyncall>'

	Exit
EndFor

&LongVarchar +=  '		</erp:ppWbsDadosClientes.Execute>'
&LongVarchar +=  '   </soapenv:Body>'
&LongVarchar +=  '</soapenv:Envelope>'

//ADICIONANDO CABEÇALHO DE COMUNICAÇÃO
&HttpClient.AddHeader('Content-Type','text/xml;charset=UTF-8')
&HttpClient.AddHeader('SOAPAction', '"ERPaction/APPWBSDADOSCLIENTES.Execute"')
&HttpClient.AddString(&LongVarchar) //ADICIONANDO PARAMETROS
&HttpClient.Execute('POST','appwbsdadosclientes.aspx') //FAZENDO POST DE COSNULTA  https://dev.efrete.com:6061/Services/LogonService.asmx?WSDL NÃO FIZ POR WSDL POIS RETORNAVA ERRO

If &HttpClient.ErrCode = 0 //sem erro de comunicação			
	&LongVarchar = ''
	&longvarchar = &HttpClient.toString()

////	&longvarchar = strReplace(&longvarchar,'<?xml version = "1.0" encoding = "utf-8"?>', '')
////	&longvarchar = strReplace(&longvarchar,'<SOAP-ENV:Envelope xmlns:SOAP-ENV="http://schemas.xmlsoap.org/soap/envelope/" xmlns:xsd="http://www.w3.org/2001/XMLSchema" xmlns:SOAP-ENC="http://schemas.xmlsoap.org/soap/encoding/" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance">', '')
////	&longvarchar = strReplace(&longvarchar,'<SOAP-ENV:Body>', '')
////	&longvarchar = strReplace(&longvarchar,'</SOAP-ENV:Body>', '')
////	&longvarchar = strReplace(&longvarchar,'</SOAP-ENV:Envelope>', '')
////	
////	&longvarchar = strReplace(&longvarchar,'<ppJASPI_Rotinas.ExecuteResponse xmlns="ADM_JASPI">', '')
////	&longvarchar = strReplace(&longvarchar,'</ppJASPI_Rotinas.ExecuteResponse>', '')
////	&longvarchar = strReplace(&longvarchar,'Sdtestruturamodulos', 'sdtEstruturaMenus')

////	&ppJaspi_RotinasSdtEstruturaMenus.FromXml(&LongVarchar)


//	&ProgressID = trim(Str(&EmpCod)) + &OqueSyncronizar.trim()
//	
//	For Each Order ProgressId
//		Where ProgressId = &ProgressID
//		ProgressIni = serverdate()
//		ProgressFin = serverdate()
//		ProgressLogXml = &longvarchar
//	When None
//		New
//			ProgressId = &ProgressID
//			ProgressIni = serverdate()
//			ProgressFin = serverdate()
//			ProgressLogXml = &longvarchar
//		EndNEw
//	EndFor
//	
//	Commit

//	&Erro = 0
Else
//	&Erro = 1

	&ProgressID = trim(Str(&EmpCod)) + &OqueSyncronizar.trim()

	For Each Order ProgressId
		Where ProgressId = &ProgressID
		ProgressIni = serverdate()
		ProgressFin = serverdate()
		ProgressLogXml = &HttpClient.ErrDescription
	When None
		New
			ProgressId = &ProgressID
			ProgressIni = serverdate()
			ProgressFin = serverdate()
			ProgressLogXml = &HttpClient.ErrDescription
		EndNEw
	EndFor

	Commit
EndIf
